import { useState } from "react";
import axios from "axios";

function Book() {
  const [data, setData] = useState({
    patientId: "123",
    doctorName: "",
    date: "",
    time: ""
  });

  const handleBook = async () => {
    try {
      const res = await axios.post("http://localhost:5000/api/appointments/book", data);
      alert(res.data.message);
    } catch (err) {
      alert(err.response.data.message);
    }
  };

  return (
    <div className="card">
      <h2>Book Appointment</h2>

      <input placeholder="Doctor Name" onChange={e => setData({...data, doctorName: e.target.value})} />
      <input type="date" onChange={e => setData({...data, date: e.target.value})} />
      <input placeholder="Time (10AM)" onChange={e => setData({...data, time: e.target.value})} />

      <button onClick={handleBook}>Book</button>
    </div>
  );
}

export default Book;
